from openai import OpenAI

def create_client(settings) -> OpenAI:
    return OpenAI(
        api_key=settings.OPENAI_API_KEY,
        base_url=settings.OPENAI_BASE_URL,
        )

def complete(messages: list[dict[str, str]], settings) -> str:
    client = create_client(settings=settings)

    response = client.chat.completions.create(
        model=settings.OPENAI_MODEL,
        messages=messages,
        )

    content = response.choices[0].message.content

    return content or ""

from repomind.config import settings
from repomind.llm.client import complete

def build_context(retrieved_chunks) -> str:
    blocks = []

    for result in retrieved_chunks:
        chunk = result.chunk

        blocks.append(
            "\n".join(
                [
                    f"文件：{chunk.path}",
                    f"行号: {chunk.start_line} - {chunk.end_line}",
                    "代码：",
                    chunk.content,    
                ]
            )
        )

    return "\n\n---\n\n".join(blocks)

def generate_answer(question: str, retrieved_chunks, settings) ->str:
    context = build_context(retrieved_chunks)

    messages = [
        {
            "role" : "system",
            "content" : (
                "你是 RepoMind，一个本地代码库分析 Agent。"    
                "你只能基于提供的嗲吗上下文问答问题。"
                "如果上下文不足，请明确说明。"
                "回答必须包含：涉及文件、实现流程、证据"
            ),
        },
        {
            "role" : "user",
            "content" : f"问题：{question}\n\n代码上下文：\n{context}",
        },    
    ]

    return complete(messages, settings)

